import React from 'react';
import styled from "styled-components";

const FormContainer = styled.form`
      display: flex;
      align-items: flex-end;
      gap: 10px;
      flex-wrap: wrap;
      background-color: #fff;
      padding: 20px;
      box-shadow: 0px 0px 5px #ccc;
      border-radius: 5px;
`;

const InputArea = styled.div`
   display: flex;
   flex-direction: column;

`;
const Input = styled.input`
   width: 120px;
   padding: 0 10px;
   border: 1px solid #bbb;
   border-radius: 5px;
   height: 40px;
`;

const Label = styled.label``;

const Button = styled.button`
    padding: 10px;
    cursor: pointer;
    border-radius: 5px;
    border: none;
    background-color: #BC2A8D;
    color: white;
    height: 42px;
`;





import { useRef } from "react";

const Form = ({ onEdit }) => {
  const ref = useRef();

  return (
    <FormContainer ref={ref} as="form">
      <InputArea>
        <Label>Nome</Label>
        <Input name="nome" />
      </InputArea>

      <InputArea>
        <Label>E-mail</Label>
        <Input name="email" type="email" />
      </InputArea>

      <InputArea>
        <Label>Username</Label>
        <Input name="user" />
      </InputArea>

      <InputArea>
        <Label>Data de Nascimento</Label>
        <Input name="data_nascimento" type="date" />
      </InputArea>

      <InputArea>
        <Label>Senha</Label>
        <Input name="password_hash" type="password" />
      </InputArea>

      <Button type="submit">SALVAR</Button>
    </FormContainer>
  );
};
export default Form;
